'use client';

import { Dispatch, SetStateAction } from 'react';

interface CampaignFilterProps {
  activeFilter: 'all' | 'emergency' | 'featured';
  onFilterChange: Dispatch<SetStateAction<'all' | 'emergency' | 'featured'>>;
}

export default function CampaignFilter({
  activeFilter,
  onFilterChange,
}: CampaignFilterProps) {
  const filters = [
    { id: 'all', label: 'All Campaigns', count: 24 },
    { id: 'emergency', label: 'Emergency', count: 8 },
    { id: 'featured', label: 'Featured', count: 6 },
  ] as const;

  return (
    <div className="flex flex-wrap gap-3 justify-center mb-12">
      {filters.map((filter) => (
        <button
          key={filter.id}
          onClick={() => onFilterChange(filter.id as 'all' | 'emergency' | 'featured')}
          className={`px-6 py-3 rounded-full font-semibold transition-all duration-300 ${
            activeFilter === filter.id
              ? 'bg-teal-600 text-white shadow-lg'
              : 'bg-gray-100 text-gray-700 hover:bg-gray-200'
          }`}
        >
          {filter.label}
          <span className={`ml-2 text-sm ${activeFilter === filter.id ? 'text-teal-100' : 'text-gray-600'}`}>
            ({filter.count})
          </span>
        </button>
      ))}
    </div>
  );
}
