'use client';

import CampaignCard from './CampaignCard';

interface Campaign {
  id: string;
  title: string;
  description: string;
  image?: string;
  category: 'all' | 'emergency' | 'featured';
  fundingGoal: number;
  amountRaised: number;
  urgencyLevel: 'Critical' | 'Urgent' | 'High' | 'Normal';
  donorCount?: number;
}

interface CampaignGridProps {
  campaigns: Campaign[];
  isLoading?: boolean;
}

export default function CampaignGrid({ campaigns, isLoading = false }: CampaignGridProps) {
  if (isLoading) {
    return (
      <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-6">
        {[...Array(6)].map((_, i) => (
          <div key={i} className="card h-96 animate-pulse">
            <div className="h-48 bg-gray-200" />
            <div className="p-6 space-y-4">
              <div className="h-6 bg-gray-200 rounded w-3/4" />
              <div className="h-4 bg-gray-200 rounded w-full" />
              <div className="h-4 bg-gray-200 rounded w-2/3" />
              <div className="h-8 bg-gray-200 rounded" />
            </div>
          </div>
        ))}
      </div>
    );
  }

  if (campaigns.length === 0) {
    return (
      <div className="text-center py-16">
        <div className="text-6xl mb-4">🔍</div>
        <h3 className="text-2xl font-bold text-gray-900 mb-2">No campaigns found</h3>
        <p className="text-gray-600">Try adjusting your filters or check back soon for new campaigns.</p>
      </div>
    );
  }

  return (
    <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-6">
      {campaigns.map((campaign) => (
        <CampaignCard key={campaign.id} {...campaign} />
      ))}
    </div>
  );
}
