'use client';

import { useState, useMemo } from 'react';
import CampaignFilter from '@/components/CampaignFilter';
import CampaignGrid from '@/components/CampaignGrid';
import { getCampaignsByCategory } from '@/lib/mockCampaigns';

export default function CampaignsPage() {
  const [activeFilter, setActiveFilter] = useState<'all' | 'emergency' | 'featured'>('all');
  const [isLoading, setIsLoading] = useState(false);

  // Get campaigns based on active filter
  const campaigns = useMemo(() => {
    setIsLoading(true);
    // Simulate loading delay
    const timer = setTimeout(() => {
      setIsLoading(false);
    }, 300);

    return () => clearTimeout(timer);
  }, []);

  const filteredCampaigns = getCampaignsByCategory(activeFilter);

  return (
    <>
      {/* Hero Section */}
      <section className="bg-gradient-to-r from-teal-50 to-blue-50 py-16 md:py-24">
        <div className="container-max">
          <div className="text-center max-w-3xl mx-auto">
            <h1 className="text-4xl md:text-5xl font-bold text-gray-900 mb-4">
              Support a Cause
            </h1>
            <p className="text-lg md:text-xl text-gray-600">
              Browse our active campaigns and make a meaningful impact in areas that matter most to you.
            </p>
          </div>
        </div>
      </section>

      {/* Campaigns Section */}
      <section className="section-padding">
        <div className="container-max">
          {/* Filter Tabs */}
          <CampaignFilter activeFilter={activeFilter} onFilterChange={setActiveFilter} />

          {/* Campaign Stats */}
          <div className="mb-8 text-center">
            <p className="text-gray-600">
              Showing <span className="font-bold text-teal-600">{filteredCampaigns.length}</span> campaign
              {filteredCampaigns.length !== 1 ? 's' : ''}
            </p>
          </div>

          {/* Campaign Grid */}
          <CampaignGrid campaigns={filteredCampaigns} isLoading={isLoading} />

          {/* Additional Info */}
          {filteredCampaigns.length > 0 && (
            <div className="mt-16 text-center">
              <p className="text-gray-600 mb-4">
                Can't find what you're looking for?
              </p>
              <a href="mailto:help@abseva.org" className="btn-secondary inline-block">
                Suggest a Campaign
              </a>
            </div>
          )}
        </div>
      </section>

      {/* Impact Section */}
      <section className="bg-gray-50 section-padding">
        <div className="container-max">
          <div className="grid grid-cols-1 md:grid-cols-3 gap-8">
            <div className="text-center">
              <div className="text-4xl font-bold text-teal-600 mb-2">₹1.5Cr+</div>
              <p className="text-gray-600">Total Funds Raised</p>
            </div>
            <div className="text-center">
              <div className="text-4xl font-bold text-teal-600 mb-2">50,000+</div>
              <p className="text-gray-600">Donors Worldwide</p>
            </div>
            <div className="text-center">
              <div className="text-4xl font-bold text-teal-600 mb-2">95%</div>
              <p className="text-gray-600">Success Rate</p>
            </div>
          </div>
        </div>
      </section>

      {/* Call to Action Section */}
      <section className="bg-gradient-to-r from-teal-600 to-teal-700 text-white section-padding">
        <div className="container-max">
          <div className="text-center max-w-2xl mx-auto">
            <h2 className="text-3xl md:text-4xl font-bold mb-4">
              Ready to Make a Difference?
            </h2>
            <p className="text-lg mb-8 text-teal-100">
              Every donation, no matter the size, creates a ripple of positive change. Choose a campaign and start your journey of impact today.
            </p>
            <a href="/donate" className="inline-block px-8 py-4 bg-orange-500 hover:bg-orange-600 text-white font-bold rounded-full transition-colors">
              Donate Now
            </a>
          </div>
        </div>
      </section>

      {/* FAQ Section */}
      <section className="section-padding">
        <div className="container-max">
          <h2 className="section-title mb-12">Campaign Questions</h2>
          <div className="grid grid-cols-1 md:grid-cols-2 gap-8 max-w-4xl mx-auto">
            <div className="bg-gray-50 p-6 rounded-lg">
              <h3 className="text-lg font-bold mb-2">How do I choose a campaign?</h3>
              <p className="text-gray-600">
                Browse through our campaigns and choose one that resonates with your values. Each campaign shows the impact your donation will have.
              </p>
            </div>
            <div className="bg-gray-50 p-6 rounded-lg">
              <h3 className="text-lg font-bold mb-2">Is my donation secure?</h3>
              <p className="text-gray-600">
                Yes! We use industry-standard encryption and partner with trusted payment providers to ensure your donation is secure.
              </p>
            </div>
            <div className="bg-gray-50 p-6 rounded-lg">
              <h3 className="text-lg font-bold mb-2">Can I track my donation?</h3>
              <p className="text-gray-600">
                Absolutely! After donating, you'll receive regular updates on how your contribution is making an impact.
              </p>
            </div>
            <div className="bg-gray-50 p-6 rounded-lg">
              <h3 className="text-lg font-bold mb-2">What if a campaign is fully funded?</h3>
              <p className="text-gray-600">
                Great news! We redirect extra funds to other urgent campaigns or use them for related initiatives with the same impact.
              </p>
            </div>
          </div>
        </div>
      </section>
    </>
  );
}
