'use client';

import Link from 'next/link';
import { Heart, TrendingUp } from 'lucide-react';

interface CampaignCardProps {
  id: string;
  title: string;
  description: string;
  image?: string;
  category: 'all' | 'emergency' | 'featured';
  fundingGoal: number;
  amountRaised: number;
  urgencyLevel: 'Critical' | 'Urgent' | 'High' | 'Normal';
  donorCount?: number;
}

export default function CampaignCard({
  id,
  title,
  description,
  image,
  category,
  fundingGoal,
  amountRaised,
  urgencyLevel,
  donorCount = 0,
}: CampaignCardProps) {
  const progressPercentage = Math.min((amountRaised / fundingGoal) * 100, 100);
  const daysLeft = Math.floor(Math.random() * 60) + 1; // Mock data

  const urgencyColors = {
    Critical: 'bg-red-100 text-red-700',
    Urgent: 'bg-orange-100 text-orange-700',
    High: 'bg-yellow-100 text-yellow-700',
    Normal: 'bg-blue-100 text-blue-700',
  };

  const urgencyBorderColors = {
    Critical: 'border-red-300',
    Urgent: 'border-orange-300',
    High: 'border-yellow-300',
    Normal: 'border-blue-300',
  };

  return (
    <div className={`card overflow-hidden hover:shadow-lg transition-all duration-300 border-l-4 ${urgencyBorderColors[urgencyLevel]}`}>
      {/* Image Section */}
      <div className="relative h-48 bg-gradient-to-br from-teal-100 to-blue-100 overflow-hidden">
        {image && (
          <img src={image} alt={title} className="w-full h-full object-cover" />
        )}
        {/* Urgency Badge */}
        <div className="absolute top-4 right-4">
          <span className={`text-xs font-bold px-3 py-1 rounded-full ${urgencyColors[urgencyLevel]}`}>
            {urgencyLevel}
          </span>
        </div>
        {/* Featured Badge */}
        {category === 'featured' && (
          <div className="absolute top-4 left-4">
            <span className="text-xs font-bold px-3 py-1 rounded-full bg-orange-100 text-orange-700">
              Featured
            </span>
          </div>
        )}
      </div>

      {/* Content Section */}
      <div className="p-6">
        {/* Title */}
        <h3 className="text-xl font-bold mb-2 line-clamp-2 text-gray-900">{title}</h3>

        {/* Description */}
        <p className="text-gray-600 text-sm mb-4 line-clamp-2">{description}</p>

        {/* Stats Row */}
        <div className="flex items-center gap-4 mb-4 text-sm">
          <div className="flex items-center gap-1">
            <Heart size={16} className="text-red-500" />
            <span className="text-gray-700">{donorCount} donors</span>
          </div>
          <div className="flex items-center gap-1">
            <TrendingUp size={16} className="text-teal-600" />
            <span className="text-gray-700">{daysLeft} days left</span>
          </div>
        </div>

        {/* Funding Information */}
        <div className="mb-4">
          <div className="flex justify-between items-center mb-2">
            <div>
              <span className="text-sm font-semibold text-gray-900">₹{(amountRaised / 100000).toFixed(1)}L</span>
              <span className="text-xs text-gray-600 ml-2">of ₹{(fundingGoal / 100000).toFixed(1)}L</span>
            </div>
            <span className="text-sm font-bold text-teal-600">{Math.round(progressPercentage)}%</span>
          </div>

          {/* Progress Bar */}
          <div className="w-full bg-gray-200 rounded-full h-2">
            <div
              className="bg-teal-600 h-2 rounded-full transition-all duration-300"
              style={{ width: `${progressPercentage}%` }}
            />
          </div>
        </div>

        {/* CTA Button */}
        <Link
          href={`/campaigns/${id}`}
          className="w-full btn-primary text-center block text-sm"
        >
          Contribute Now
        </Link>
      </div>
    </div>
  );
}
